var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"들어오게, 메데이아 경.","JPN":"入りたまえ、メデイア卿。","ENG":"Come in, Dame Medea.","TWN":"請進，美狄亞。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어머, 소름. 발걸음 소리만 듣고 저인 걸 알아채셨어요?","JPN":"あら、鳥肌が。足音だけでよくわかりましたね。","ENG":"Oh my, goosebumps. You recognized me just from my footsteps?","TWN":"哎呀，真讓人起雞皮疙瘩。光聽腳步聲就知道是我了嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"약속을 잡은 건 경이 아닌가. 이 시간에 올 사람이라면 정해져 있지.","JPN":"訪問を申し出たのは君の方だろう。この時間に来る者は決まっている。","ENG":"You're the one who arranged this meeting. Who else would come at this hour?","TWN":"不是你約好的嗎？這個時間會來的人不是已經定好了嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"최근 여러 일이 겹친 탓에 일찍 이야기를 나누지 못한 건 미안하게 생각하네.","JPN":"最近色々な事件が重なり、もっと早く話の場を作れなかったことは申し訳ないと思っている。","ENG":"Apologies for not speaking sooner. Too much has been happening lately.","TWN":"最近因為各種事情重疊，沒能早點和你聊聊，真是抱歉啊。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아뇨. 이런 시국에 주교가 본부에 박혀 있는 게 더 문제죠.","JPN":"いえ、こんな状況に主教が本部に引きこもっていたら、そっちのほうが問題ですもの。","ENG":"No need to apologize. What's more troubling is a bishop hiding in the main office during times like these.","TWN":"不。這種情況下，主教窩在總部才是更大的問題。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"예정에도 없던 원로 자리까지 맡았으니, 윗분들이 열심히 일하지 않으면 곤란하답니다?","JPN":"予定にもなかった元老の座まで引き受けてしまったので、上の方々にはもっと頑張っていただかないと。","ENG":"And now I've taken on a Council seat I didn't plan for. If the higher-ups don't work hard, we're in trouble.","TWN":"既然連原本沒有計劃的元老職位都擔任了，如果上面的人不努力工作的話，那就麻煩了喔？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"……미리 말하지만, 한솔 경은 아직 원로 자리를 맡기에는 경험이 부족하네.","JPN":"……言っておくが、ヤガミ君はまだ元老を務めるには経験不足だ。","ENG":"...Let me first say, Sir Hansol still lacks the experience to serve on the Council.","TWN":"……提前說一句，楊瀚還缺乏擔任元老職位的經驗。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"쯧.","JPN":"ちっ。","ENG":"Tsk.","TWN":"嘖。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데… 손님이 왔는데 보는 척도 안 하시네요?","JPN":"ところで……客が来たのに顔を見もしないんですね。","ENG":"By the way... not even a glance at your guest?","TWN":"不過……客人來了，你卻連看都不看一眼？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아까부터 뭘 그렇게 보고 계세요?","JPN":"先程から何をそんなに見つめているんですか？","ENG":"What's caught your eye so much?","TWN":"你從剛才開始一直在看什麼呢？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"알고 있나, 메데이아 경? 별의 인도자에 대한 전승은 수없이 많지만, 모든 전승에는 동일한 문구가 들어간다네.","JPN":"知っているかね、メデイア卿？　星の導き手の伝承は数え切れぬほど多いが、すべての伝承に共通している部分がある。","ENG":"Are you aware, Dame Medea? There are many legends about the Star Guide, but all of them share one line.","TWN":"你知道嗎，美狄亞？雖然關於星之引導者的傳承有無數次，但所有傳承中都有相同的語句。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"먼 훗날. 멸망을 목도한 아이들이 길을 잃었을 때…….","JPN":"遠い未来、滅びを迎えた子どもたちが道に迷った時……","ENG":"So that one day, when the children who witnessed the world's ruin lost their way...","TWN":"遙遠的未來。當目睹毀滅的孩子們迷失方向時……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"인도자가 새긴 별빛이, 그들을 구원의 길로 이끌 것이다.","JPN":"導き手が刻んだ星の光が、彼らを救いへと導いてくれる。","ENG":"The starlight carved by the Guide will lead them down the path of salvation.","TWN":"引導者刻下的星光，將引領他們走向救贖之路。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"기사단에서 질리도록 들어서 잘 알고 있어요. 갑자기 그건 왜요?","JPN":"騎士団で耳にタコができるほど聞かされたから、よく知っています。でもそれがどうしたんですか？","ENG":"Yes, yes. The Order's drilled it into us enough. Why bring it up now?","TWN":"在騎士團裡聽得夠多了，我很清楚。突然問這個幹什麼？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"옛 전승에 따라 인도자께서 남기신 무구는 기사단을 지탱하는 뼈대나 다름없었네.","JPN":"古き伝承によって、導き手が残した武具は、騎士団を支える柱にほかならない。","ENG":"According to legend, the Armaments left by the Guide are the very backbone of the Order.","TWN":"根據古老傳說，引導者留下的武器幾乎是支撐騎士團的骨架。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"제각각 다른 열두 가문이 정의라는 단어 아래 하나로 뭉칠 수 있었던 이유.","JPN":"それぞれ異なる12家門が、正義という言葉の下に一つに集められた理由。","ENG":"They are the reason twelve distinct houses could unite under the banner of justice.","TWN":"各自不同的十二個家族能夠在正義這個詞下團結成一體的原因。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그것이 별의 무구고, 원로들이 전통을 중요시 여기는 것 또한 이와 일맥상통하지.","JPN":"それが星の武具であり、元老たちが伝統を重んじる理由でもある。","ENG":"They are the Star Armaments, and our reverence for tradition follows that same spirit.","TWN":"那是星之武具，長老們重視傳統也是與此一脈相承的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"때문에 별의 무구야말로 진실된 답으로 여기는 것이 기사단의 순리이거늘…….","JPN":"よって、星の武具こそ真の答えと捉えるのが、騎士団の理であるが……","ENG":"That's why the Armaments are treated as absolute truth in the Order...","TWN":"因此，將星之武具視為真正的答案才是騎士團的正道……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"무구의 선택을 받은 이들이 하나둘씩 방황하니, 이제는 나조차 혼란스럽군.","JPN":"武具に選ばれし者たちがひとり、またひとりと迷いだしているこの状況に、私は非常に混乱している。","ENG":"But when those chosen by the Armaments begin to waver, even I find myself in doubt.","TWN":"被無垢選擇的人一個個開始迷茫，現在連我也感到困惑了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"인도자의 전승도 와전된 모양이죠. 너무 어렵게 생각하지 마세요.","JPN":"導き手の伝承も、引き継がれるうちに内容が変わったのでしょう。難しく考えないでください。","ENG":"Then maybe the legend's been distorted over time. Don't overthink it.","TWN":"引導者的傳承似乎也被誤解了。別想得太複雜。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아니면, 저희가 전승의 내용을 잘못 파악하고 있거나.","JPN":"もしかしたら、伝承に対する私たちの解釈が間違っているのかもしれませんし。","ENG":"Or maybe we've just misunderstood it from the start.","TWN":"或者，是我們對傳承的內容理解錯誤。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"기관이 보내준 문서는 잘 읽었네. 클리포트 게임 현장에서 구원기사단의 무구가 사라졌다지.","JPN":"機関が送ってくれた文書は読ませてもらった。クリフォトゲームの現場で救世騎士団の武具が消えたらしいな。","ENG":"I read the report from the Institution. You said the Knights of Redemption's Armament vanished during the Qliphoth Game?","TWN":"機關送來的檔我已經看過了。聽說在逆卡巴拉遊戲現場，救贖騎士團的武器消失了。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"자네의 요청으로 현장에 추가 인력을 파견한 결과. 과거와 동일한 흔적이 발견되었네.","JPN":"君の要請で現場に追加人員を派遣した結果、過去と同じ痕跡が見つかったよ。","ENG":"We dispatched more personnel at your request, and they found the same traces as before.","TWN":"根據你的請求派遣了額外人員到現場。發現了與過去相同的痕跡。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그러지 않길 바랬지만…… 자네의 추측이 맞았던 모양이야.","JPN":"間違いであって欲しかったが……どうやら君の推測は当たっていたようだ。","ENG":"I hoped we were wrong... but it seems your suspicion was right.","TWN":"雖然希望不是這樣……看來你的猜測是對的。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"와. 설마 싶었는데 걔네들 용케 살아있었네요?","JPN":"あら。まさかとは思ったけど、あいつらよく生き延びましたね。","ENG":"Wow. Didn't expect it, but they're alive after all?","TWN":"哇。沒想到他們居然還活著呢？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그래. 어쩌면 우리가 전임 기사단장의 희생을 물거품으로 만든 걸지도 모르겠군.","JPN":"ああ。もしかしたら、私たちは前騎士団長の犠牲を水の泡にしてしまったのかもしれないな。","ENG":"Yes. It may be that we've made the former captain's sacrifice meaningless.","TWN":"是啊。或許我們讓前任騎士團長的犧牲化為泡影了吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};